#include<bits/stdc++.h>
using namespace std;
string n;
int main(){
	getline(cin,n);
	for(int i=0;i<n.size();i++){
		if((n[i]>'A'&&n[i]<='Z')||(n[i]>'a'&&n[i]<='z')){
			cout<<char(n[i]-1);
		}else if(n[i]=='A'){
			cout<<'Z';
		}else if(n[i]=='a'){
			cout<<'z';
		}else{
			cout<<n[i];
		}
	}
	return 0;
}
